#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
int n, q, u, v, tree[MAXN][2], depth[MAXN], parent[MAXN][20];
void dfs(int node, int p) {
    parent[node][0] = p;
    depth[node] = depth[p] + 1;
    for (int i = 1; i < 20; i++)
        parent[node][i] = parent[parent[node][i-1]][i-1];
    if (tree[node][0] != -1)
        dfs(tree[node][0], node);
    if (tree[node][1] != -1)
        dfs(tree[node][1], node);
}
int lca(int u, int v) {
    if (depth[u] < depth[v])
        u ^= v ^= u ^= v;
    for (int i = 19; i >= 0; i--)
        if (depth[parent[u][i]] >= depth[v])
            u = parent[u][i];
    if (u == v)
        return u;
    for (int i = 19; i >= 0; i--)
        if (parent[u][i] != parent[v][i]) {
            u = parent[u][i];
            v = parent[v][i];
        }
    return parent[u][0];
}
int path_length(int u, int v) {
    int l = lca(u, v);
    return depth[u] + depth[v] - 2 * depth[l];
}
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        scanf("%d %d", &n, &q);
        for (int i = 0; i < n; i++)
            tree[i][0] = tree[i][1] = -1;
        for (int i = 0; i < n - 1; i++) {
            int p;
            scanf("%d", &p);
            if (tree[p-1][0] == -1)
                tree[p-1][0] = i + 1;
            else
                tree[p-1][1] = i + 1;
        }
        dfs(0, -1);
        while (q--) {
            scanf("%d %d", &u, &v);
            printf("%d\n", path_length(u-1, v-1));
        }
    }
    return 0;
}

