rl.on('line', (input) => {
    lines.push(input);
});
rl.on('close', () => {
    let l = 0;
    const t = +lines[l++];
    for (let i = 0; i < t; i++) {
        const [n, q] = lines[l++].trim().split(' ').map(Number);
        const tree = Array.from({ length: n }, () => []);
        const parent = Array.from({ length: n }, () => Array(20).fill(-1));
        const depth = Array(n).fill(0);
        const edges = lines[l++].trim().split(' ').map(Number);
        for (let j = 0; j < n - 1; j++) {
            tree[edges[j] - 1].push(j + 1);
        }
        function dfs(node, p) {
            parent[node][0] = p;
            depth[node] = depth[p] + 1;
            for (let k = 1; k < 20; k++)
                parent[node][k] = parent[parent[node][k - 1]][k - 1];
            for (const child of tree[node])
                dfs(child, node);
        }
        dfs(0, -1);
        function lca(u, v) {
            if (depth[u] < depth[v])
                [u, v] = [v, u];
            for (let k = 19; k >= 0; k--)
                if (depth[parent[u][k]] >= depth[v])
                    u = parent[u][k];
            if (u === v)
                return u;
            for (let k = 19; k >= 0; k--)
                if (parent[u][k] !== parent[v][k]) {
                    u = parent[u][k];
                    v = parent[v][k];
                }
            return parent[u][0];
        }
        function path_length(u, v) {
            const l = lca(u, v);
            return depth[u] + depth[v] - 2 * depth[l];
        }
        for (let j = 0; j < q; j++) {
            const [u, v] = lines[l++].trim().split(' ').map(Number);
            console.log(path_length(u - 1, v - 1));
        }
    }
});

